{
  "meta": {
    "created_at": "2026-04-16T14:00:00+08:00",
    "author": "Alex Zhang",
    "status": "active",
    "version": "1.0.0",
    "description": "Integration test configuration for Project Orion API endpoints"
  },
  "test_suite_name": "Project Orion API Integration Tests",
  "base_url": "https://api.oriontech.example.com/v1",
  "timeout_seconds": 30,
  "test_created_at": "2026-04-16T14:00:00+08:00",
  "endpoints_under_test": [
    {
      "path": "/projects",
      "methods": ["GET", "POST"],
      "description": "Project management endpoints"
    },
    {
      "path": "/tasks",
      "methods": ["GET", "POST", "PUT", "DELETE"],
      "description": "Task management endpoints"
    },
    {
      "path": "/users",
      "methods": ["GET", "POST"],
      "description": "User management endpoints"
    },
    {
      "path": "/auth/login",
      "methods": ["POST"],
      "description": "Authentication endpoint"
    },
    {
      "path": "/reports",
      "methods": ["GET"],
      "description": "Reporting and analytics endpoints"
    }
  ],
  "environment": {
    "name": "staging",
    "region": "ap-northeast-1",
    "database": "staging_db",
    "cache_enabled": true
  },
  "retry_policy": {
    "max_retries": 3,
    "backoff_seconds": 2,
    "retry_on": [500, 502, 503, 504]
  },
  "authentication": {
    "type": "bearer_token",
    "token_env_var": "ORION_API_TEST_TOKEN"
  }
}
